export default {
  selectActivations(input) {
    const memory = input.strategyMemory && typeof input.strategyMemory === "object" ? input.strategyMemory : {}
    const phase = memory.phase === "break" || input.phaseNumber >= 2 ? "break" : "mirror"
    return {
