}

const wallSide = (grid) => {
  const walls = grid.cells.filter((cell) => cell.contents === "WALL")
  const top = walls.filter((cell) => cell.dy < 0).length
  const right = walls.filter((cell) => cell.dx > 0).length
  const bottom = walls.filter((cell) => cell.dy > 0).length
